import React, { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useClient } from '../contexts/ClientContext';
import { 
  Calendar, 
  RefreshCw, 
  Download, 
  FileSpreadsheet, 
  FileImage, 
  ChevronLeft, 
  ChevronRight, 
  Edit3, 
  Trash2, 
  X, 
  Save 
} from 'lucide-react';

// Types
type FunnelStage = 'awareness' | 'interest' | 'consideration' | 'download' | 'registration' | 'conversion' | 'retention';

interface Asset {
  id: string;
  title: string;
  dueDate: string;
  channel: string;
  funnelStage: FunnelStage;
  campaign: string;
  description?: string;
  startDate?: string;
  mediaType?: 'image' | 'video' | 'document' | 'campaign';
  status?: 'planned' | 'in-progress' | 'completed' | 'delayed';
}

interface Period {
  id: string;
  name: string;
  startDate: string;
  endDate: string;
}

interface Campaign {
  id: string;
  name: string;
  color: string;
}

// Configuration
const FUNNEL_STAGES = [
  { id: 'awareness', name: 'AWARENESS', color: '#FFE4E1', description: 'Build brand recognition and visibility' },
  { id: 'interest', name: 'INTEREST', color: '#E6F3FF', description: 'Generate curiosity and engagement' },
  { id: 'consideration', name: 'CONSIDERATION', color: '#F0FFF0', description: 'Provide detailed product information' },
  { id: 'download', name: 'DOWNLOAD', color: '#FFF8DC', description: 'Encourage app downloads and trials' },
  { id: 'registration', name: 'REGISTRATION', color: '#F5F0FF', description: 'Capture user information and preferences' },
  { id: 'conversion', name: 'CONVERSION', color: '#FFE4B5', description: 'Drive purchases and subscriptions' },
  { id: 'retention', name: 'RETENTION', color: '#E0FFFF', description: 'Maintain engagement and loyalty' }
];

const DEFAULT_PERIODS: Period[] = [
  { id: 'period1', name: 'NOVEMBER – MARCH', startDate: '2024-11-01', endDate: '2025-03-31' },
  { id: 'period2', name: 'APRIL – JUNE', startDate: '2025-04-01', endDate: '2025-06-30' }
];

const DEFAULT_CAMPAIGNS: Campaign[] = [
  { id: 'credit-card', name: 'Credit Card', color: '#1976D2' },
  { id: 'insurance', name: 'Insurance', color: '#388E3C' },
  { id: 'new-product', name: 'New Product', color: '#F57F17' }
];

// Mock API calls - replace with actual implementation
const roadmapApi = {
  getAssets: async (clientId: string) => {
    // Integration with Content Management API
    return { assets: [] };
  },
  createAsset: async (asset: Partial<Asset>) => {
    console.log('Creating asset:', asset);
    return asset;
  },
  updateAsset: async (id: string, updates: Partial<Asset>) => {
    console.log('Updating asset:', id, updates);
    return updates;
  },
  deleteAsset: async (id: string) => {
    console.log('Deleting asset:', id);
    return { success: true };
  },
  exportRoadmap: async (format: string, clientId: string) => {
    console.log(`Exporting roadmap as ${format} for client ${clientId}`);
    return { downloadUrl: '#' };
  },
  syncWithCMS: async (clientId: string) => {
    console.log('Syncing with CMS for client:', clientId);
    return { synchronized: true, assetsAdded: 5 };
  }
};

const RoadmapGenerator: React.FC = () => {
  const { selectedClient } = useClient();
  const [assets, setAssets] = useState<Asset[]>([]);
  const [periods] = useState<Period[]>(DEFAULT_PERIODS);
  const [campaigns] = useState<Campaign[]>(DEFAULT_CAMPAIGNS);
  const [selectedPeriod, setSelectedPeriod] = useState<string>(DEFAULT_PERIODS[0].id);
  const [currentMonth, setCurrentMonth] = useState<number>(0);
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
  const [zoomLevel, setZoomLevel] = useState<number>(1);

  // Form state for asset creation/editing
  const [assetForm, setAssetForm] = useState({
    title: '',
    dueDate: '',
    channel: '',
    funnelStage: 'awareness' as FunnelStage,
    campaign: DEFAULT_CAMPAIGNS[0].id,
    description: '',
    startDate: ''
  });

  const queryClient = useQueryClient();

  // Fetch assets from API
  const { data: assetsData, isLoading: assetsLoading } = useQuery({
    queryKey: ['roadmap-assets', selectedClient?.id],
    queryFn: () => selectedClient ? roadmapApi.getAssets(selectedClient.id) : Promise.resolve({ assets: [] }),
    enabled: !!selectedClient,
  });

  // Update local state when API data changes
  useEffect(() => {
    if (assetsData?.assets) {
      setAssets(assetsData.assets);
    } else if (selectedClient && assets.length === 0) {
      // Initialize with sample data only if no data from API and client is selected
      const sampleAssets: Asset[] = [
        {
          id: '1',
          title: 'Credit Card Social Media Campaign',
          dueDate: '2024-12-15',
          channel: 'Social Media',
          funnelStage: 'awareness',
          campaign: 'credit-card',
          description: 'Instagram and Facebook ads for credit card promotion',
          startDate: '2024-12-01',
          mediaType: 'campaign',
          status: 'planned'
        },
        {
          id: '2',
          title: 'Insurance Product Demo Video',
          dueDate: '2025-01-10',
          channel: 'YouTube',
          funnelStage: 'consideration',
          campaign: 'insurance',
          description: 'Educational video explaining insurance benefits',
          startDate: '2024-12-20',
          mediaType: 'video',
          status: 'in-progress'
        },
        {
          id: '3',
          title: 'App Download Landing Page',
          dueDate: '2025-02-01',
          channel: 'Website',
          funnelStage: 'download',
          campaign: 'new-product',
          description: 'Optimized landing page for app downloads',
          startDate: '2025-01-15',
          mediaType: 'document',
          status: 'planned'
        },
        {
          id: '4',
          title: 'Customer Loyalty Email Series',
          dueDate: '2025-03-15',
          channel: 'Email',
          funnelStage: 'retention',
          campaign: 'credit-card',
          description: 'Automated email series for customer retention',
          startDate: '2025-03-01',
          mediaType: 'campaign',
          status: 'planned'
        }
      ];
      setAssets(sampleAssets);
    }
  }, [assetsData, selectedClient, assets.length]);

  // Mock API calls - replace with actual API integration
  const fetchAssets = async (): Promise<Asset[]> => {
    // This would integrate with your CMS/media API
    return [];
  };

  const saveAsset = async (asset: Partial<Asset>): Promise<Asset> => {
    const newAsset: Asset = {
      id: Date.now().toString(),
      title: asset.title || '',
      dueDate: asset.dueDate || '',
      channel: asset.channel || '',
      funnelStage: asset.funnelStage || 'awareness',
      campaign: asset.campaign || DEFAULT_CAMPAIGNS[0].id,
      description: asset.description || '',
      startDate: asset.startDate || '',
      mediaType: 'campaign',
      status: 'planned'
    };
    setAssets(prev => [...prev, newAsset]);
    return newAsset;
  };

  const updateAsset = async (id: string, updates: Partial<Asset>): Promise<Asset> => {
    const existingAsset = assets.find(a => a.id === id);
    if (!existingAsset) throw new Error('Asset not found');

    const updatedAsset = { ...existingAsset, ...updates };
    setAssets(prev => prev.map(a => a.id === id ? updatedAsset : a));
    return updatedAsset;
  };

  const deleteAsset = async (id: string): Promise<void> => {
    setAssets(prev => prev.filter(a => a.id !== id));
  };

  // Mutations
  const updateAssetMutation = useMutation({
    mutationFn: ({ id, updates }: { id: string; updates: Partial<Asset> }) =>
      roadmapApi.updateAsset(id, updates),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['roadmap-assets'] });
      setEditingAsset(null);
    }
  });

  const deleteAssetMutation = useMutation({
    mutationFn: roadmapApi.deleteAsset,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['roadmap-assets'] });
    }
  });

  // Event handlers
  const handleAssetSave = async (e: React.FormEvent) => {
    e.preventDefault();
    
    try {
      if (editingAsset) {
        await updateAsset(editingAsset.id, assetForm);
        setEditingAsset(null);
      } else {
        await saveAsset(assetForm);
      }
      
      // Reset form
      setAssetForm({
        title: '',
        dueDate: '',
        channel: '',
        funnelStage: 'awareness',
        campaign: DEFAULT_CAMPAIGNS[0].id,
        description: '',
        startDate: ''
      });
    } catch (error) {
      console.error('Error saving asset:', error);
    }
  };

  const handleAssetDelete = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this asset?')) {
      await deleteAsset(id);
    }
  };

  const startEditingAsset = (asset: Asset) => {
    setEditingAsset(asset);
    setAssetForm({
      title: asset.title,
      dueDate: asset.dueDate,
      channel: asset.channel,
      funnelStage: asset.funnelStage,
      campaign: asset.campaign,
      description: asset.description || '',
      startDate: asset.startDate || ''
    });
  };

  const getAssetsForStage = (stage: FunnelStage) => {
    return assets.filter(asset => asset.funnelStage === stage);
  };

  const getFunnelStageConfig = (stage: FunnelStage) => {
    return FUNNEL_STAGES.find(s => s.id === stage) || FUNNEL_STAGES[0];
  };

  const getCurrentPeriod = () => {
    return periods.find(p => p.id === selectedPeriod) || periods[0];
  };

  const getMonthsForPeriod = (period: Period) => {
    const start = new Date(period.startDate);
    const end = new Date(period.endDate);
    const months = [];
    
    const current = new Date(start);
    while (current <= end) {
      months.push({
        name: current.toLocaleDateString('en-US', { month: 'long' }),
        year: current.getFullYear(),
        date: new Date(current)
      });
      current.setMonth(current.getMonth() + 1);
    }
    
    return months;
  };

  const periodMonths = getMonthsForPeriod(getCurrentPeriod());

  // Export functionality
  const handleExport = async (format: 'pdf' | 'excel' | 'image') => {
    if (!selectedClient) {
      alert('Please select a client first');
      return;
    }

    try {
      if (format === 'image') {
        // For image export, we'll use html2canvas or similar
        const element = document.querySelector('.roadmap-container');
        if (element) {
          // This would integrate with html2canvas or similar library
          console.log('Exporting as image...');
          alert('Image export functionality would be implemented here');
        }
      } else {
        const result = await roadmapApi.exportRoadmap(format, selectedClient.id);
        console.log(`Exported roadmap as ${format}:`, result);
        alert(`Roadmap exported as ${format.toUpperCase()}`);
      }
    } catch (error) {
      console.error('Export failed:', error);
      alert('Export failed. Please try again.');
    }
  };

  // CMS Sync functionality
  const handleSyncWithCMS = async () => {
    if (!selectedClient) return;

    try {
      const result = await roadmapApi.syncWithCMS(selectedClient.id);
      console.log('Sync result:', result);
      // Refresh assets after sync
      queryClient.invalidateQueries({ queryKey: ['roadmap-assets'] });
      alert('Successfully synchronized with Content Management system');
    } catch (error) {
      console.error('Sync failed:', error);
      alert('Sync failed. Please try again.');
    }
  };

  const [draggedAsset, setDraggedAsset] = useState<Asset | null>(null);

  // Drag and drop handlers
  const handleDragStart = (e: React.DragEvent, asset: Asset) => {
    setDraggedAsset(asset);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetStage: FunnelStage) => {
    e.preventDefault();

    if (!draggedAsset) return;

    // Update the asset's funnel stage
    updateAsset(draggedAsset.id, { funnelStage: targetStage });
    setDraggedAsset(null);
  };

  if (!selectedClient) {
    return (
      <div className="roadmap-container bg-white">
        <div className="text-center py-12">
          <div className="w-16 h-16 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
            <Calendar className="w-8 h-8 text-gray-400" />
          </div>
          <h3 className="text-lg font-medium text-gray-900 mb-2">
            Client Selection Required
          </h3>
          <p className="text-gray-500 mb-6">
            Please select a client from the top navigation to access the roadmap generator.
          </p>
        </div>
      </div>
    );
  }

  if (assetsLoading) {
    return (
      <div className="roadmap-container bg-white">
        <div className="text-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto"></div>
          <p className="mt-4 text-gray-500">Loading roadmap data...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="roadmap-container bg-white min-h-screen">
      {/* Header */}
      <div className="bg-white border-b border-gray-200 px-6 py-4">
        <div className="flex items-center justify-between mb-4">
          <h1 className="text-2xl font-bold text-gray-900">
            Marketing Roadmap Generator - {selectedClient.name}
          </h1>
          <div className="flex items-center space-x-3">
            <button
              onClick={handleSyncWithCMS}
              className="inline-flex items-center px-3 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 text-sm"
            >
              <RefreshCw className="w-4 h-4 mr-1" />
              Sync CMS
            </button>
            
            <div className="relative group">
              <button className="inline-flex items-center px-3 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 text-sm">
                <Download className="w-4 h-4 mr-1" />
                Export
              </button>
              <div className="absolute top-full right-0 mt-1 w-32 bg-white border border-gray-300 rounded-md shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-10">
                <button
                  onClick={() => handleExport('pdf')}
                  className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 flex items-center"
                >
                  <Download className="w-3 h-3 mr-2" />
                  PDF
                </button>
                <button
                  onClick={() => handleExport('excel')}
                  className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 flex items-center"
                >
                  <FileSpreadsheet className="w-3 h-3 mr-2" />
                  Excel
                </button>
                <button
                  onClick={() => handleExport('image')}
                  className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 flex items-center"
                >
                  <FileImage className="w-3 h-3 mr-2" />
                  Image
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Period and Month Navigation */}
        <div className="flex items-center justify-between">
          <select
            value={selectedPeriod}
            onChange={(e) => setSelectedPeriod(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          >
            {periods.map(period => (
              <option key={period.id} value={period.id}>{period.name}</option>
            ))}
          </select>

          <div className="flex items-center space-x-2">
            <button
              onClick={() => setCurrentMonth(Math.max(0, currentMonth - 1))}
              disabled={currentMonth === 0}
              className="p-1 rounded-md bg-gray-200 hover:bg-gray-300 disabled:opacity-50"
            >
              <ChevronLeft className="w-4 h-4" />
            </button>
            <span className="text-sm text-gray-600">
              {periodMonths[currentMonth]?.name} {periodMonths[currentMonth]?.year}
            </span>
            <button
              onClick={() => setCurrentMonth(Math.min(periodMonths.length - 1, currentMonth + 1))}
              disabled={currentMonth === periodMonths.length - 1}
              className="p-1 rounded-md bg-gray-200 hover:bg-gray-300 disabled:opacity-50"
            >
              <ChevronRight className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="p-6">
        <div className="roadmap-grid" style={{ transform: `scale(${zoomLevel})`, transformOrigin: 'top left' }}>
          {/* Campaign Legend */}
          <div className="mb-6">
            <h3 className="text-lg font-medium text-gray-900 mb-3">Campaign Categories</h3>
            <div className="flex space-x-4">
              {campaigns.map(campaign => (
                <div key={campaign.id} className="flex items-center">
                  <div 
                    className="w-4 h-4 rounded mr-2" 
                    style={{ backgroundColor: campaign.color }}
                  ></div>
                  <span className="text-sm text-gray-700">{campaign.name}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Content Integration Notice */}
          <div className="mb-4 p-3 bg-blue-50 border border-blue-200 rounded-lg">
            <div className="flex items-center">
              <RefreshCw className="w-5 h-5 text-blue-500 mr-2" />
              <p className="text-sm text-blue-700">
                <strong>Content Integration:</strong> Assets displayed here are loaded from your Content Management system.
                To add new assets, use the Content Management page. You can organize and schedule existing assets across funnel stages here.
              </p>
            </div>
          </div>

          {/* Funnel Stages */}
          {FUNNEL_STAGES.map(stage => (
            <div key={stage.id} className="funnel-stage">
              <div className="flex items-center mb-3">
                <div
                  className="w-4 h-4 rounded mr-3"
                  style={{ backgroundColor: stage.color }}
                ></div>
                <h3 className="text-lg font-semibold text-gray-900">{stage.name}</h3>
                <span className="ml-2 text-sm text-gray-500">({getAssetsForStage(stage.id as FunnelStage).length})</span>
              </div>
              <p className="text-sm text-gray-600 mb-4">{stage.description}</p>
              
              <div
                className="min-h-32 p-4 border-2 border-dashed border-gray-300 rounded-lg transition-colors"
                style={{ backgroundColor: stage.color }}
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, stage.id as FunnelStage)}
              >
                {getAssetsForStage(stage.id as FunnelStage).map((asset, index) => (
                  <div
                    key={asset.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, asset)}
                    className="bg-white p-3 rounded-md shadow-sm mb-2 cursor-move border border-gray-200 hover:shadow-md transition-shadow"
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <h4 className="font-medium text-gray-900 text-sm">{asset.title}</h4>
                        <p className="text-xs text-gray-600 mt-1">{asset.channel}</p>
                        <p className="text-xs text-gray-500 mt-1">Due: {asset.dueDate}</p>
                        <div 
                          className="w-2 h-2 rounded inline-block mt-1" 
                          style={{ backgroundColor: campaigns.find(c => c.id === asset.campaign)?.color || '#gray' }}
                        ></div>
                      </div>
                      <div className="flex space-x-1">
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            startEditingAsset(asset);
                          }}
                          className="p-1 hover:bg-gray-100 rounded"
                        >
                          <Edit3 className="w-3 h-3 text-gray-500" />
                        </button>
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            handleAssetDelete(asset.id);
                          }}
                          className="p-1 hover:bg-gray-100 rounded"
                        >
                          <Trash2 className="w-3 h-3 text-red-500" />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
                
                {getAssetsForStage(stage.id as FunnelStage).length === 0 && (
                  <div className="text-center py-8 text-gray-500">
                    <p className="text-sm">Drop assets here or sync with CMS to populate</p>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Asset Editing Modal */}
      {editingAsset && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-2xl mx-4 max-h-screen overflow-y-auto">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-semibold text-gray-900">Edit Asset Schedule</h2>
              <button
                onClick={() => setEditingAsset(null)}
                className="p-1 hover:bg-gray-100 rounded"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleAssetSave} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Asset Title
                </label>
                <input
                  type="text"
                  value={assetForm.title}
                  onChange={(e) => setAssetForm(prev => ({ ...prev, title: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  required
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Start Date
                  </label>
                  <input
                    type="date"
                    value={assetForm.startDate}
                    onChange={(e) => setAssetForm(prev => ({ ...prev, startDate: e.target.value }))}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Due Date
                  </label>
                  <input
                    type="date"
                    value={assetForm.dueDate}
                    onChange={(e) => setAssetForm(prev => ({ ...prev, dueDate: e.target.value }))}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    required
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Channel
                  </label>
                  <input
                    type="text"
                    value={assetForm.channel}
                    onChange={(e) => setAssetForm(prev => ({ ...prev, channel: e.target.value }))}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Funnel Stage
                  </label>
                  <select
                    value={assetForm.funnelStage}
                    onChange={(e) => setAssetForm(prev => ({ ...prev, funnelStage: e.target.value as FunnelStage }))}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    required
                  >
                    {FUNNEL_STAGES.map(stage => (
                      <option key={stage.id} value={stage.id}>{stage.name}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Campaign
                </label>
                <select
                  value={assetForm.campaign}
                  onChange={(e) => setAssetForm(prev => ({ ...prev, campaign: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  required
                >
                  {campaigns.map(campaign => (
                    <option key={campaign.id} value={campaign.id}>{campaign.name}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Description
                </label>
                <textarea
                  value={assetForm.description}
                  onChange={(e) => setAssetForm(prev => ({ ...prev, description: e.target.value }))}
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  placeholder="Asset description or notes..."
                />
              </div>

              <div className="flex space-x-3 pt-4">
                <button
                  type="submit"
                  disabled={updateAssetMutation.isPending}
                  className="flex-1 inline-flex items-center justify-center px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
                >
                  <Save className="w-4 h-4 mr-2" />
                  Update Asset Schedule
                </button>
                <button
                  type="button"
                  onClick={() => setEditingAsset(null)}
                  className="px-4 py-2 text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Mobile responsive styles */}
      <style>{`
        @media (max-width: 768px) {
          .roadmap-grid {
            transform: scale(0.8) !important;
            overflow-x: auto;
          }
          
          .funnel-stage {
            min-width: 300px;
            margin-bottom: 1.5rem;
          }
        }
        
        .funnel-stage {
          margin-bottom: 2rem;
          padding: 1rem;
          border: 1px solid #e5e7eb;
          border-radius: 0.5rem;
          background: #fafafa;
        }
        
        .roadmap-container {
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', sans-serif;
        }
      `}</style>
    </div>
  );
};

export default RoadmapGenerator;
